// 1. Captura telefone em qualquer estrutura
// ================================
const item = $input.first().json;

const rawPhone = String(
  item.phone?.[0]?.value || 
  item.person_id?.phone?.[0]?.value || 
  ''
);

// ================================
// 2. Remove tudo que não for número
// ================================
let cleaned = rawPhone.replace(/\D/g, '');

// ================================
// 3. Remove 55 duplicado
// ================================
if (cleaned.startsWith('55') && cleaned.length > 13) {
  cleaned = cleaned.substring(2);
}

// ================================
// 4. Ajusta formato
// ================================
if (cleaned.length === 11) {

  // Celular sem 55
  // Ex: 11999998888
  cleaned = '55' + cleaned;

} else if (cleaned.length === 10) {

  // Fixo sem 55
  // Ex: 1133334444
  cleaned = '55' + cleaned;

} else if (cleaned.length === 13 && cleaned.startsWith('55')) {

  // Já correto
  // Ex: 5511999998888

} else if (cleaned.length === 12 && cleaned.startsWith('55')) {

  // Telefone fixo com 55
  // Ex: 551133334444

} else {

  // Formato inválido
  cleaned = '';
}

// ================================
// 5. Retorno
// ================================
return [{
  json: {
    telefoneOriginal: rawPhone,
    telefoneFormatado: cleaned
  }
}];

